/**
 * Detector generator - creates pattern detector functions
 */

import { resolve } from 'node:path';
import { writeFile, mkdir } from 'node:fs/promises';
import { toPascalCase } from './utils.js';

export interface DetectorGenOptions {
  name: string;
}

export interface GenResult {
  files: { path: string; action: 'created' }[];
}

export function generateDetectorContent(name: string): string {
  const pascal = toPascalCase(name);
  return `/**
 * @generated by @flusk/cli
 */
import type { CorrelationResult } from './correlate-with-traces.function.js';
import type { DetectedPattern } from './detect-patterns.function.js';
import { getLogger } from '@flusk/logger';

const logger = getLogger().child({ module: 'detect-${name}' });

/**
 * Detects ${name} patterns in profiling data.
 * TODO: implement detection logic
 */
export function detect${pascal}(
  correlations: CorrelationResult[],
): DetectedPattern[] {
  const patterns: DetectedPattern[] = [];

  for (const { llmCall, relatedHotspots } of correlations) {
    for (const hotspot of relatedHotspots) {
      // TODO: add detection criteria
      logger.debug({ hotspot: hotspot.functionName, llmCallId: llmCall.id }, 'pattern found');
      patterns.push({
        pattern: '${name}',
        severity: 'medium',
        description: \`\${hotspot.functionName}: TODO describe\`,
        suggestion: 'TODO: add suggestion',
        metadata: { hotspot, llmCallId: llmCall.id },
      });
    }
  }

  logger.info({ count: patterns.length }, '${name} detection complete');
  return patterns;
}
`;
}

export function generateDetectorTestContent(name: string): string {
  const pascal = toPascalCase(name);
  return `/**
 * @generated by @flusk/cli
 */
import { describe, it, expect } from 'vitest';

describe('detect${pascal}', () => {
  it('should return empty array for no correlations', async () => {
    const { detect${pascal} } = await import(
      '../detect-${name}.function.js'
    );
    expect(detect${pascal}([])).toEqual([]);
  });
});
`;
}

export async function generateDetector(opts: DetectorGenOptions): Promise<GenResult> {
  const root = process.cwd();
  const dir = resolve(root, 'packages/business-logic/src/profile-session');
  const testDir = resolve(dir, '__tests__');
  await mkdir(testDir, { recursive: true });

  const result: GenResult = { files: [] };

  const filePath = `packages/business-logic/src/profile-session/detect-${opts.name}.function.ts`;
  await writeFile(resolve(root, filePath), generateDetectorContent(opts.name), 'utf-8');
  result.files.push({ path: filePath, action: 'created' });

  const testPath = `packages/business-logic/src/profile-session/__tests__/detect-${opts.name}.function.test.ts`;
  await writeFile(resolve(root, testPath), generateDetectorTestContent(opts.name), 'utf-8');
  result.files.push({ path: testPath, action: 'created' });

  return result;
}
